interface ERC721Interface {
  function ownerOf(uint256 _tokenId) external view returns (address _owner);
  function approve(address _to, uint256 _tokenId) external;
  function getApproved(uint256 _tokenId) external view returns (address);
  function isApprovedForAll(address _owner, address _operator) external view returns (bool);
  function safeTransferFrom(address _from, address _to, uint256 _tokenId) external;
  function supportsInterface(bytes4) external view returns (bool);
}

if (initialDistributionRatio < 1000) {
  // Cannot use `getTotalBalance()` here because the factory has not yet sent the gold.
  uint256 totalGrant = releaseSchedule.amountReleasedPerPeriod.mul(
    releaseSchedule.numReleasePeriods
  );
  // Initial ratio is expressed to 3 significant figures: [0, 1000].
  maxDistribution = totalGrant.mul(initialDistributionRatio).div(1000);
} else {
  maxDistribution = MAX_UINT;
}

if (deprecated_commitments[proposer] != 0) {
  require(randomness != 0, "randomness cannot be zero if there is a previous commitment");
  bytes32 expectedCommitment = computeCommitment(randomness);
  require(
    expectedCommitment == deprecated_commitments[proposer],
    "commitment didn't match the posted randomness"
  );
} else {
  require(randomness == 0, "randomness should be zero if there is no previous commitment");
}

if (!rollbackTesting.value) {
    // Trigger rollback using upgradeTo from the new implementation
    rollbackTesting.value = true;
    Address.functionDelegateCall(
        newImplementation,
        abi.encodeWithSignature("upgradeTo(address)", oldImplementation)
    );
    rollbackTesting.value = false;
    // Check rollback was effective
    require(oldImplementation == _getImplementation(), "ERC1967Upgrade: upgrade breaks further upgrades");
    // Finally reset to the new implementation and log the upgrade
    _upgradeTo(newImplementation);
}

if (msgSenderBalance < _amount) {
    require(msgSenderBalance + msg.value >= _amount, "NativeOFTV2: Insufficient msg.value");

    // user can cover difference with additional msg.value ie. wrapping
    uint mintAmount = _amount - msgSenderBalance;
    _mint(address(msg.sender), mintAmount);

    // update the messageFee to take out mintAmount
    messageFee = msg.value - mintAmount;
} else {
    messageFee = msg.value;
}

if (bridgehub.whitelistedSettlementLayers(config.gatewayChainId)) {
    console.log("Chain already whitelisted as settlement layer");
} else {
    bytes memory data = abi.encodeCall(bridgehub.registerSettlementLayer, (config.gatewayChainId, true));
    Utils.executeUpgrade({
        _governor: config.governance,
        _salt: bytes32(0),
        _target: address(bridgehub),
        _data: data,
        _value: 0,
        _delay: 0
    });
    console.log("Gateway whitelisted as settlement layer");
}

try
            executorQuoterRouter.quoteExecution(
                dstChainId,
                peerAddr,
                address(this),
                quoterAddress,
                requestBytes,
                relayInstructions
            )
        returns (uint256 executorFee) {
            gasCost = executorFee + wormhole.messageFee();
        } catch {
            gasCost = 0;
        }

function _checkFilterOperator(address operator) internal view virtual {
    // Check registry code length to facilitate testing in environments without a deployed registry.
    if (address(OPERATOR_FILTER_REGISTRY).code.length > 0) {
        // under normal circumstances, this function will revert rather than return false, but inheriting contracts
        // may specify their own OperatorFilterRegistry implementations, which may behave differently
        if (!OPERATOR_FILTER_REGISTRY.isOperatorAllowed(address(this), operator)) {
            revert OperatorNotAllowed(operator);
        }
    }
}

for (uint256 i = 0; i < EnumerableSet.length(otherBeneficiariesAddresses); i++) {
  address beneficiary = otherBeneficiariesAddresses.get(i);
  Beneficiary storage otherBeneficiary = otherBeneficiaries[beneficiary];

  uint256 amount = _calculateDistributeAmounts(
    otherBeneficiary.fraction,
    totalFractionOfOtherBeneficiariesAndCarbonFixidity,
    tokenState.toDistribute
  );

  _executePayment(tokenAddress, beneficiary, amount);
}

_deployedContracts.stateTransition.chainTypeManagerProxy = _deployInternal(
    "TransparentUpgradeableProxy",
    "TransparentUpgradeableProxy.sol",
    abi.encode(
        _deployedContracts.stateTransition.chainTypeManagerImplementation,
        _deployedContracts.stateTransition.chainTypeManagerProxyAdmin,
        abi.encodeCall(ChainTypeManager.initialize, (diamondInitData))
    ),
    innerConfig
);

if (proxyAdmin.code.length == 0) {
    // IMPORTANT: note that it requires `ProxyAdmin` to be one of the factory deps for the upgrade transaction.
    ProxyAdmin admin = new ProxyAdmin();
    SystemContractHelper.mimicCallWithPropagatedRevert(
        _l2LegacySharedBridge,
        proxyAdmin,
        abi.encodeCall(ITransparentUpgradeableProxy.changeAdmin, (address(admin)))
    );
    proxyAdmin = address(admin);
}

if (liquidated) {

    IRewardDistributor rewardDistributor = IRewardDistributor(contractRegistry.getContractAddress(REWARD_DISTRIBUTOR_HASH));
    IStakingManager stakingManager = IStakingManager(contractRegistry.getContractAddress(STAKING_MANAGER_HASH));

    rewardDistributor.liquidateAccount(nftId);
    stakingManager.liquidateAccount(nftId, msg.sender);

    emit AccountLiquidated(nftId);
} else {
    emit AccountLiquidationStarted(nftId);
}

struct TokenState {
  address handler;
  FixidityLib.Fraction maxSlippage;
  // Max amounts that can be burned in a day for a token
  uint256 dailySellLimit;
  // Max amounts that can be burned today for a token
  uint256 currentDaySellLimit;
  uint256 toDistribute;
  // Historical amounts burned by this contract
  uint256 pastBurn;
  uint256 lastLimitDay;
  uint256 toBurn;
}

if (del.bondedAmount == 0) {
    // Delegator no longer delegated to anyone if it does not have a bonded amount
    del.delegateAddress = address(0);
    // Delegator does not have a start round if it is no longer delegated to anyone
    del.startRound = 0;

    if (transcoderPool.contains(msg.sender)) {
        resignTranscoder(msg.sender);
    }
}

if (totalLockedGold == 0) {
  delegated.totalDelegatedCeloFraction = delegated
    .totalDelegatedCeloFraction
    .subtract(currentDelegateeInfo.percentage)
    .add(percentageToDelegate);
  currentDelegateeInfo.percentage = percentageToDelegate;

  emit CeloDelegated(
    delegatorAccount,
    delegateeAccount,
    FixidityLib.unwrap(percentageToDelegate),
    currentDelegateeInfo.currentAmount
  );
  return;
}

struct SortitionSumTree {
    uint K; // The maximum number of childs per node.
    // We use this to keep track of vacant positions in the tree after removing a leaf. This is for keeping the tree as balanced as possible without spending gas on moving nodes around.
    uint[] stack;
    uint[] nodes;
    // Two-way mapping of IDs to node indexes. Note that node index 0 is reserved for the root node, and means the ID does not have a node.
    mapping(bytes32 => uint) IDsToNodeIndexes;
    mapping(uint => bytes32) nodeIndexesToIDs;
}

address allocationManagerImpl = address(
    new AllocationManager(
        IDelegationManager(result.delegationManager),
        IPauserRegistry(result.pauserRegistry),
        IPermissionController(result.permissionController),
        configData.allocationManager.deallocationDelay,
        configData.allocationManager.allocationConfigurationDelay,
        configData.version
    )
);

struct Config {
    address bridgehub;
    address ctmDeploymentTracker;
    address chainTypeManagerProxy;
    address sharedBridgeProxy;
    address governance;
    uint256 gatewayChainId;
    address gatewayChainAdmin;
    address gatewayAccessControlRestriction;
    address gatewayChainProxyAdmin;
    address l1NullifierProxy;
    bytes gatewayDiamondCutData;
    bytes l1DiamondCutData;
}

if (address(safetyModule) != address(0)) {
    // stkWELL snapshots (ERC20WithSnapshot) are keyed by block.timestamp,
    // not block.number — query getPriorVotes with a timestamp.
    uint _priorVotes = safetyModule.getPriorVotes(
        _user,
        block.timestamp - 1
    );
    _result = Votes(
        _priorVotes,
        safetyModule.balanceOf(_user),
        address(0)
    );
}

struct VaultV2Info {
    address vault;
    string name;
    string symbol;
    address asset;
    string assetName;
    string assetSymbol;
    uint8 assetDecimals;
    uint256 totalAssets;
    uint256 totalSupply;
    uint256 underlyingPrice; // USD price with 18 decimals
    address owner;
    address curator;
    address adapterRegistry;
    AdapterInfo[] adapters;
}

if (
    functionSelector == StrategyChainlinkFloor.executeFixedDiscountCollectionOfferStrategyWithTakerAsk.selector
) {
    if (floorPrice < discount) {
        // A special selector is returned to differentiate with OrderInvalid
        // since the maker can potentially become valid again
        return (isValid, DiscountGreaterThanFloorPrice.selector);
    }
}

struct AccessManagedStorage {
    address _authority;

    bool _consumingSchedule;
}

// keccak256(abi.encode(uint256(keccak256("openzeppelin.storage.AccessManaged")) - 1)) & ~bytes32(uint256(0xff))
bytes32 private constant AccessManagedStorageLocation = 0xf3177357ab46d8af007ab3fdb9af81da189e1068fefdc0073dca88a2cab40a00;

function _getAccessManagedStorage() private pure returns (AccessManagedStorage storage $) {
    assembly {
        $.slot := AccessManagedStorageLocation
    }
}

ChainCreationParams memory chainCreationParams = ChainCreationParams({
    genesisUpgrade: _deployedContracts.stateTransition.genesisUpgrade,
    genesisBatchHash: _config.genesisRoot,
    genesisIndexRepeatedStorageChanges: uint64(_config.genesisRollupLeafIndex),
    genesisBatchCommitment: _config.genesisBatchCommitment,
    diamondCut: diamondCut,
    forceDeploymentsData: _config.forceDeploymentsData
});

if (msg.sender == address(this)) {
    bytes memory array = msg.data;
    uint256 index = msg.data.length;
    assembly {
        // Load the 32 bytes word from memory with the address on the lower 20 bytes, and mask those.
        sender := and(
            mload(add(array, index)),
            0xffffffffffffffffffffffffffffffffffffffff
        )
    }
} else {
    sender = msg.sender;
}
